#ifdef __cplusplus
extern "C" {
#endif

#include <omp.h>
#include <math.h>

#define fp float

#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
	fp x, y, z;

} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;

} FOUR_VECTOR;

typedef struct nei_str
{


	int x, y, z;
	int number;
	long offset;

} nei_str;

typedef struct box_str
{


	int x, y, z;
	int number;
	long offset;


	int nn;
	nei_str nei[26];

} box_str;

typedef struct par_str
{

	fp alpha;

} par_str;

typedef struct dim_str
{


	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;


	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;

} dim_str;

void kernel_cpu(par_str d_par_cpu,
				dim_str d_dim_cpu,
				box_str *d_box_cpu,
				FOUR_VECTOR *d_rv_cpu,
				fp *d_qv_cpu,
				FOUR_VECTOR *d_fv_cpu)
{
	int bx;

	fp a2 = 2.0f * d_par_cpu.alpha * d_par_cpu.alpha;

	#pragma omp parallel for schedule(static)
	for (bx = 0; bx < d_dim_cpu.number_boxes; bx++) {
		int first_i = d_box_cpu[bx].offset;

		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		int wtx;

		// Load rA_shared
		for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
			rA_shared[wtx] = d_rv_cpu[first_i + wtx];
		}

		for (int k = 0; k < (1 + d_box_cpu[bx].nn); k++) {
			int pointer = (k == 0) ? bx : d_box_cpu[bx].nei[k - 1].number;
			int first_j = d_box_cpu[pointer].offset;

			// Load rB_shared and qB_shared
			for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rB_shared[wtx] = d_rv_cpu[first_j + wtx];
				qB_shared[wtx] = d_qv_cpu[first_j + wtx];
			}

			// Compute forces for particles in box bx
			#pragma omp parallel for schedule(static)
			for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				fp fv_v = 0.0f;
				fp fv_x = 0.0f;
				fp fv_y = 0.0f;
				fp fv_z = 0.0f;

				for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					fp r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx], rB_shared[j]);
					fp u2 = a2 * r2;
					fp vij = expf(-u2);
					fp fs = 2.0f * vij;
					fp dx = rA_shared[wtx].x - rB_shared[j].x;
					fp dy = rA_shared[wtx].y - rB_shared[j].y;
					fp dz = rA_shared[wtx].z - rB_shared[j].z;
					fp fxij = fs * dx;
					fp fyij = fs * dy;
					fp fzij = fs * dz;
					fv_v += qB_shared[j] * vij;
					fv_x += qB_shared[j] * fxij;
					fv_y += qB_shared[j] * fyij;
					fv_z += qB_shared[j] * fzij;
				}

				#pragma omp atomic
				d_fv_cpu[first_i + wtx].v += fv_v;
				#pragma omp atomic
				d_fv_cpu[first_i + wtx].x += fv_x;
				#pragma omp atomic
				d_fv_cpu[first_i + wtx].y += fv_y;
				#pragma omp atomic
				d_fv_cpu[first_i + wtx].z += fv_z;
			}
		}
	}
}

#ifdef __cplusplus
}
#endif
